// SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

contract Voting{

    struct Candidate {
        string name;
        uint voteCount;
    }

    struct Election {
        address creator;
        uint startTime;
        uint endTime;
        bool ended;
        Candidate[] candidates;
        mapping(address => bool) hasVoted;
    }

    uint public electionCount;
    mapping(uint => Election) public elections;

    // EVENTS
    event ElectionCreated(uint electionId, address creator);
    event CandidateAdded(uint electionId, string name);
    event Voted(uint electionId, address voter, uint candidateIndex);
    event ElectionEnded(uint electionId);

    // CREATE ELECTION (AI CŨNG TẠO ĐƯỢC)
    function createElection(
        uint _startTime,
        uint _endTime
    ) external {
        require(_endTime > _startTime, "Invalid time");

        electionCount++;

        Election storage e = elections[electionCount];
        e.creator = msg.sender;
        e.startTime = _startTime;
        e.endTime = _endTime;

        emit ElectionCreated(electionCount, msg.sender);
    }

    // ADD CANDIDATE
    function addCandidate(uint electionId, string calldata name) external {
        Election storage e = elections[electionId];

        require(msg.sender == e.creator, "Not creator");

        e.candidates.push(Candidate(name, 0));

        emit CandidateAdded(electionId, name);
    }

    // VOTE
    function vote(uint electionId, uint candidateIndex) external {
        Election storage e = elections[electionId];

        require(block.timestamp >= e.startTime, "Not started");
        require(block.timestamp <= e.endTime, "Ended");
        require(!e.hasVoted[msg.sender], "Already voted");
        require(candidateIndex < e.candidates.length, "Invalid candidate");

        e.candidates[candidateIndex].voteCount++;
        e.hasVoted[msg.sender] = true;

        emit Voted(electionId, msg.sender, candidateIndex);
    }

    // END EARLY
    function endElection(uint electionId) external {
        Election storage e = elections[electionId];

        require(msg.sender == e.creator, "Not creator");

        e.endTime = block.timestamp;
        e.ended = true;

        emit ElectionEnded(electionId);
    }

    // GET CANDIDATES
    function getCandidates(uint electionId)
        external
        view
        returns (Candidate[] memory)
    {
        return elections[electionId].candidates;
    }
}
